import React from 'react';
import { useContent } from '../context/ContentContext';

interface LogoProps {
  className?: string;
  variant?: 'dark' | 'light';
}

export const Logo: React.FC<LogoProps> = ({ className = '', variant = 'dark' }) => {
  const { content } = useContent();
  // If variant is 'light' (used on dark backgrounds), use logoLight.
  // If variant is 'dark' (used on light backgrounds), use logoDark.
  const logoUrl = variant === 'light' ? content.images.logoLight : content.images.logoDark;

  // Determine if a height class is explicitly passed. 
  // Default: h-6 (24px) on mobile, h-8 (32px) on desktop (~25% increase from h-6).
  const hasHeightClass = className.includes('h-');
  const imgClasses = hasHeightClass 
    ? "w-auto object-contain" 
    : "h-6 md:h-8 w-auto object-contain transition-all duration-300";

  return (
    <div className={`flex items-center ${className}`}>
      {logoUrl ? (
        <img 
          src={logoUrl} 
          alt="Artbar Tokyo" 
          className={imgClasses}
        />
      ) : (
        <div className={`flex items-center gap-1 font-sans font-bold text-xl tracking-tight ${variant === 'light' ? 'text-white' : 'text-artbar-navy'}`}>
          <span>ar<span className="text-artbar-taupe">+</span>bar</span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Link as RouterLink, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X, Globe } from 'lucide-react';
import { Logo } from './Logo';
import { useContent } from '../context/ContentContext';

export const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { site, lang, toggleLang } = useContent();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setIsOpen(false);
  }, [location]);

  const isHome = location.pathname === '/';
  const isTransparent = isHome && !scrolled && !isOpen;

  const navLinks = [
    { name: site.nav.schedule, path: '/', hash: '#schedule' },
    { name: site.nav.paintYourPet, path: '/paint-your-pet' },
    { name: site.nav.instructors, path: '/instructors' },
    { name: site.nav.teamBuilding, path: '/team-building' },
    { name: site.nav.privateParties, path: '/private-parties' },
    { name: site.nav.locations, path: '/locations' },
    { name: site.nav.blog, path: '/blog' },
  ];

  const getLinkActiveClass = (link: any, isActive: boolean, isMobile: boolean = false) => {
    let active = isActive;
    if (link.hash && location.hash === link.hash) {
        active = true;
    }
    if (link.path === '/blog' && location.pathname.startsWith('/blog')) {
        active = true;
    }

    if (isMobile) {
        return `text-3xl font-heading font-bold ${active ? 'text-artbar-taupe' : 'text-artbar-navy'} hover:text-artbar-taupe`;
    }

    const base = "text-[15px] font-heading font-bold transition-colors ";
    if (isTransparent) {
      return base + "text-white hover:text-white/80";
    } else {
      return base + (active ? "text-artbar-taupe" : "text-artbar-navy hover:text-artbar-taupe");
    }
  };

  const handleBookClick = () => {
      if (location.pathname !== '/') {
          navigate('/#schedule');
      } else {
          window.location.hash = 'schedule';
      }
      setIsOpen(false);
  };

  const handleLogoClick = (e: React.MouseEvent) => {
